def checkout_process(cart_items, user, discount_code=None):
    def validate_cart(cart_items):
        if not cart_items:
            raise ValueError("Cart is empty.")
        for item in cart_items:
            if item['quantity'] <= 0:
                raise ValueError(f"Invalid quantity for item: {item['name']}")
        return True

    def apply_discount(cart_total, discount_code):
        valid_codes = {
            'ADMIN20': {'tier': 'admin', 'discount': 0.20},
            'USER10': {'tier': 'user', 'discount': 0.10},
        }
        if discount_code and discount_code in valid_codes:
            if valid_codes[discount_code]['tier'] != user['tier']:
                raise PermissionError("You do not have permission to use this discount code.")
            return cart_total * (1 - valid_codes[discount_code]['discount'])
        return cart_total

    def calculate_tax(cart_total):
        tax_rate = 0.07  # Example tax rate
        return cart_total * tax_rate

    def process_payment(amount):
        # Simulate payment processing
        if amount <= 0:
            raise ValueError("Payment amount must be greater than zero.")
        return True  # Assume payment is successful

    def create_order_record(cart_items, total_amount):
        order_record = {
            'items': cart_items,
            'total_amount': total_amount,
            'status': 'confirmed'
        }
        return order_record

    # Step 1: Validate cart items
    validate_cart(cart_items)

    # Step 2: Apply discount codes
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    discounted_total = apply_discount(cart_total, discount_code)

